insert into public.exam_questions (station, question_id, ord, prompt, max_marks, model_answers, images) values
  ('Rhinology', 'Q0', 0, 'Case: Acute invasive fungal rhinosinusitis. 62-year-old, emergency presentation: right nasal obstruction for 3 days, low-grade fever, right facial pain for 2 days, right facial and peri-orbital swelling for 1 day.', 0, '[]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R1', 1, 'What further information / risk factors do you need from the history?', 10, '["Renal transplant", "On immunosuppressants and steroids", "Poorly controlled diabetes mellitus", "Haematological malignancy (leukaemia, lymphoma), especially with neutropenia", "Iatrogenic immunosuppression (transplant, steroids)", "Advanced HIV"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R2', 2, 'Describe the nasal endoscopy findings.', 8, '["Necrotic / black eschar of mucosa and turbinate", "Pale, insensate or discoloured mucosa", "Crusting and tissue destruction suggestive of invasive fungal disease"]'::jsonb, '["/images/exam/rhino-endoscopy.jpg"]'::jsonb),
  ('Rhinology', 'R3', 3, 'What would you look for on cranial nerve and eye examination?', 6, '["Right lateral rectus paralysis (CN VI palsy)", "Assess other cranial neuropathies and orbital involvement"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R4', 4, 'What investigations would you do next?', 6, '["Blood tests — may show neutropenia", "Urgent radiology — CT scan of sinuses"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R5', 5, 'What is your suspicion, and what do you see on the CT?', 6, '["Acute invasive fungal rhinosinusitis", "Sinus opacification and mucosal thickening (non-specific)"]'::jsonb, '["/images/exam/rhino-ct-1.jpg", "/images/exam/rhino-ct-2.jpg"]'::jsonb),
  ('Rhinology', 'R6', 6, 'What is the role of CT in diagnosing acute invasive fungal rhinosinusitis?', 10, '["Define the anatomy", "Non-specific sinus opacification and mucosal thickening", "Peri-antral fat stranding indicating extension beyond the antrum", "Bone erosion, thinning and/or destruction"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R7', 7, 'What is the next step (biopsy) and what are the histopathology findings?', 10, '["Biopsy — if available frozen section for a quick result", "Tissue invasion and angio-invasion by fungus", "Broad, ribbon-like, non-septate hyphae branching at more than 90 degrees with vessel-wall invasion", "Mucormycosis (not aspergillus, which is septate and branches at less than 45 degrees)"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R8', 8, 'Do you want any other investigation, and why?', 6, '["MRI", "Superior soft-tissue assessment and extra-sinus extension"]'::jsonb, '["/images/exam/rhino-mri-1.jpg", "/images/exam/rhino-mri-2.jpg"]'::jsonb),
  ('Rhinology', 'R9', 9, 'What is the role of MRI?', 10, '["Superior in soft tissue", "Superior for extra-sinus extension (orbital fat, extra-ocular muscles, pterygoid fossa, intracranial)", "Non-specific T1 and T2 mucosal thickening with secretions", "Black turbinate sign on T1+contrast — local lack of mucosal enhancement indicating ischaemia/necrosis", "Sinus mucosal lack of enhancement on T1+contrast"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R10', 10, 'Which is better for this diagnosis, CT or MRI?', 4, '["Both complementary — CT for bone/anatomy, MRI for soft tissue and extra-sinus/intracranial extension"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R11', 11, 'What is the treatment?', 4, '["Amphotericin B", "Urgent surgical debridement", "Reverse immunosuppression / control underlying condition"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R12', 12, 'What are the possible side effects of Amphotericin B and what monitoring is required?', 10, '["Renal function — creatinine, BUN, urine output (nephrotoxicity is the commonest serious complication)", "Electrolytes — K, Mg, Ca, phosphate wasting; hypokalaemia increases digoxin toxicity", "CBC — anaemia, bone-marrow suppression", "Hepatic function — bilirubin, ALT, AST", "Infusion reactions — fever, chills, rigors, nausea, vomiting, BP changes", "IV site — phlebitis"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R13', 13, 'What is the role of surgery — the limit of debridement and the second look?', 6, '["Surgical debridement back to healthy, bleeding (viable) tissue", "Second look to confirm clearance and reassess for ongoing progression"]'::jsonb, '[]'::jsonb),
  ('Rhinology', 'R14', 14, 'How are CT and MRI findings in allergic fungal rhinosinusitis different?', 4, '["CT: double density, more extensive involvement/pansinusitis, sinus expansion, bone thinning and remodelling", "MRI: T2 signal void, T1 hypo- or iso-intense, peripheral ring enhancement on T1+contrast"]'::jsonb, '[]'::jsonb),
  ('Otology', 'Q0', 0, 'Case: Chronic otitis media with cholesteatoma. 35-year-old male with recurrent left ear discharge and progressive hearing loss over 3 years. Discharge is foul-smelling, occasionally blood-tinged, poorly responsive to oral antibiotics. History of recurrent childhood ear infections. (For the investigations section, provide the candidate with your prepared PTA and HRCT temporal bones.)', 0, '[]'::jsonb, '[]'::jsonb),
  ('Otology', 'O1', 1, '[History] Key symptoms you would ask about to confirm cholesteatoma?', 5, '["Foul-smelling, painless, persistent otorrhea", "Progression of hearing loss and presence of tinnitus", "Previous ear surgery, trauma or grommet insertion", "Laterality and exact duration"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O2', 2, '[History] Red-flag symptoms to rule out complications?', 10, '["Vertigo / severe dizziness — labyrinthine fistula", "Facial weakness or asymmetry — facial nerve palsy", "Severe headache, fever, photophobia, neck stiffness — meningitis / intracranial abscess", "Post-auricular swelling, pain, erythema — mastoiditis / subperiosteal abscess", "Altered mental status, lethargy, seizures — intracranial involvement"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O3', 3, '[History · Senior] How does the pathophysiology of acquired cholesteatoma explain the symptoms?', 5, '["Retraction pocket theory — squamous epithelial migration into the middle ear cleft", "Keratin debris accumulation provides a nidus for infection", "Secondary infection (Pseudomonas, Proteus, anaerobes) causes the foul smell", "Osteolysis by inflammatory mediators / enzymes (collagenases, osteoclasts) → granulation and blood-tinged discharge"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O4', 4, '[Examination] Systematic steps of the head & neck examination?', 5, '["General inspection incl. post-auricular region for scars/swelling", "Otoscopy/microscopy of the normal (right) ear first", "Then the affected left ear (aural microsuction may be needed)", "Tuning fork tests — Rinne and Weber", "Complete cranial nerve exam with focus on the facial nerve (CN VII)"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O5', 5, '[Examination] Classic otoscopic findings of an attic (pars flaccida) cholesteatoma?', 5, '["Retraction pocket in the pars flaccida", "Pearly white keratin debris and crusting over the attic", "Erosion of the scutum (lateral epitympanic wall)", "Granulation tissue or aural polyp from the attic"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O6', 6, '[Examination · Senior] Fistula test — how performed, positive result, and what it indicates?', 5, '["Apply positive and negative pressure to the EAC (pneumatic otoscope or tragal pressure)", "Positive = induced nystagmus and vertigo", "Indicates a labyrinthine fistula, commonly the lateral semicircular canal"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O7', 7, '[Examination · Senior] Large inflammatory polyp obscuring the TM — outpatient approach?', 5, '["Gentle aural microsuction to clear discharge", "Topical vasoconstrictor and steroid drops to reduce the polyp", "NEVER blindly avulse, snare or pull the polyp in clinic", "Reason: may be attached to the facial nerve, stapes or dura → facial palsy, deafness or CSF leak"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O8', 8, '[Investigations] Interpret the provided PTA and tympanogram.', 5, '["Type of hearing loss — conductive, sensorineural or mixed", "Degree of loss / pure tone average", "Size of the air-bone gap", "Tympanogram type (e.g. Type B) or not testable due to perforation/discharge"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O9', 9, '[Investigations] Primary imaging modality and what you look for?', 5, '["HRCT temporal bones without contrast", "Extent of soft tissue / disease", "Ossicular chain and scutum status", "Bony boundaries — tegmen tympani, lateral semicircular canal, facial nerve canal"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O10', 10, '[Investigations · Senior] Describe the key findings on the provided HRCT temporal bones.', 10, '["Non-dependent soft tissue density in the epitympanum / Prussak''s space / mastoid", "Erosion or blunting of the scutum", "Ossicular erosion (long process of incus, stapes superstructure)", "Tegmen tympani integrity — intact, eroded or dehiscent", "Lateral semicircular canal — intact vs fistulous tract"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O11', 11, '[Investigations · Senior] When would you order a non-EPI DWI-MRI?', 5, '["Differentiate cholesteatoma from cholesterol granuloma, scar or effusion (restricts diffusion, hyperintense)", "Evaluate residual/recurrent disease post-op, especially before a planned second look", "Assess suspected intracranial complications (dural involvement, brain abscess)"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O12', 12, '[Management] Initial conservative / medical management while awaiting surgery?', 5, '["Aural microsuction and clearance of debris", "Topical antibiotic + steroid drops (e.g. ciprofloxacin/dexamethasone)", "Strict water precautions to keep the ear dry"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O13', 13, '[Management] Goals of cholesteatoma surgery, in order of priority?', 5, '["1) Make the ear safe — eradicate disease, prevent intra/extracranial complications", "2) Provide a dry, self-cleansing ear", "3) Preserve or restore hearing (ossiculoplasty)"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O14', 14, '[Management · Senior] Canal Wall Up vs Canal Wall Down — pros, cons and indications?', 10, '["CWU pros — maintains normal anatomy, no cavity care, allows water sports", "CWU cons — higher residual/recurrence, limited exposure, often needs second-look/MRI surveillance", "CWD pros — lower recurrence, excellent exposure, residual disease easily monitored in clinic", "CWD cons — lifelong cavity care, water precautions, possibly worse hearing, caloric vertigo", "CWD indications — extensive/unresectable disease (sinus tympani, facial recess), poor ET function, sclerotic/contracted mastoid, non-compliant follow-up, complications (large fistula, intracranial)"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O15', 15, '[Management · Senior] Intra-operative 2 mm lateral semicircular canal fistula — management?', 5, '["Recognize it and stop dissection there; leave the matrix over the fistula until the end of the case", "Avoid suctioning directly over the fistula (prevents SNHL)", "If matrix peels off easily — remove and cover the defect (fascia, perichondrium or bone pate)", "If densely adherent or large — leave matrix in situ and exteriorize via Canal Wall Down"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O16', 16, '[Post-op] Immediate and early post-operative complications for consent?', 5, '["Facial nerve palsy", "Sensorineural hearing loss / dead ear", "Vertigo, dizziness, tinnitus", "Bleeding, hematoma, wound infection", "Altered taste (chorda tympani)"]'::jsonb, '[]'::jsonb),
  ('Otology', 'O17', 17, '[Post-op · Senior] Long-term follow-up after CWU mastoidectomy to monitor recurrence?', 5, '["Regular clinical examination and otomicroscopy", "Post-op audiometry at 3–6 months", "Non-EPI DWI MRI at 12–18 months for residual/recurrent disease", "Planned second-look surgery if MRI is positive, equivocal or unavailable"]'::jsonb, '[]'::jsonb),
  ('Pediatric', 'Q0', 0, 'Case: 3-month-old infant presenting with a neck mass.', 0, '[]'::jsonb, '["/images/exam/peds-neck-mass.jpg"]'::jsonb),
  ('Pediatric', 'P1', 1, 'What would you ask in the history?', 15, '["Present at birth vs appeared later; rate of growth", "Change in size with crying or straining", "Skin colour change / overlying skin", "Airway, feeding or breathing symptoms", "Preceding infection or rapid enlargement", "Transillumination noticed; family history"]'::jsonb, '[]'::jsonb),
  ('Pediatric', 'P2', 2, 'What would you look for on examination and which investigations?', 15, '["Site, size, consistency, compressibility; transillumination (positive in lymphatic malformation)", "Overlying skin changes; airway assessment", "Ultrasound first-line", "MRI to define extent and tissue planes", "CT in selected cases"]'::jsonb, '[]'::jsonb),
  ('Pediatric', 'P3', 3, 'Read the image — what is your diagnosis?', 15, '["Multicystic / macro- or micro-cystic lesion", "Diagnosis: lymphatic malformation (cystic hygroma)"]'::jsonb, '["/images/exam/peds-imaging.jpg", "/images/exam/peds-image3.jpg"]'::jsonb),
  ('Pediatric', 'P4', 4, 'On CT and MRI, what are the differences between a haemangioma and a lymphatic malformation?', 15, '["Haemangioma — solid, intensely enhancing, flow voids, T2 hyperintense lobulated solid mass", "Lymphatic malformation — cystic, non-enhancing (or rim/septal enhancement only), fluid-fluid levels, very T2 hyperintense, trans-spatial"]'::jsonb, '[]'::jsonb),
  ('Pediatric', 'P5', 5, 'Theory of development, staging system, and modalities of treatment?', 20, '["Development — sequestration of lymphatic sacs that fail to connect with the venous system", "Staging — de Serres staging (I–V, by uni/bilateral and above/below the hyoid)", "Treatment — observation, sclerotherapy, surgery, and medical therapy (sirolimus)"]'::jsonb, '[]'::jsonb),
  ('Pediatric', 'P6', 6, 'Surgery versus sclerotherapy — advantages, disadvantages, and the most-used agents?', 20, '["Surgery — potential complete excision but risk to nerves/vessels and recurrence", "Sclerotherapy — less invasive, often needs repeated sessions, good for macrocystic disease", "Common agents — OK-432 (picibanil), bleomycin, doxycycline, ethanol, sodium tetradecyl sulfate"]'::jsonb, '[]'::jsonb);
